const input = $input.first()?.json || $json || {};
const message = input.message || {};
const callbackQuery = input.callback_query || null;
const callbackMessage = callbackQuery?.message || {};
const callbackData = String(callbackQuery?.data || '');
const text = callbackData || String(message.text || '').trim();
const chatId = String(callbackMessage.chat?.id || callbackQuery?.from?.id || message.chat?.id || '');
const lower = text.toLowerCase();

const SNOOZE_OPTIONS = {
  '1h': { runs: 1, label: '1 hour' },
  '4h': { runs: 4, label: '4 hours' },
  '12h': { runs: 12, label: '12 hours' },
  '24h': { runs: 24, label: '24 hours' },
};

let intent = 'UNKNOWN';
let post_id = '';
let command = '';
let command_args = '';
let like_amount = '';
let likes_prompt_required = false;
let snooze_duration_key = '';
let snooze_duration_label = '';
let snooze_runs_remaining = null;
let snooze_duration_invalid = '';
let start_payload = '';
const callback_query_id = callbackQuery?.id || '';
const callback_message_id = callbackMessage.message_id ? String(callbackMessage.message_id) : '';
const callback_message_text = String(callbackMessage.text || callbackMessage.caption || '');
const input_source = callbackQuery ? 'callback' : 'command';

function setSnoozeDuration(key) {
  const option = SNOOZE_OPTIONS[String(key || '').toLowerCase()];
  if (!option) return false;
  snooze_duration_key = String(key).toLowerCase();
  snooze_duration_label = option.label;
  snooze_runs_remaining = option.runs;
  return true;
}

const snoozeDurationMatch = callbackData.match(/^snooze_duration:([0-9]{1,19}):(1h|4h|12h|24h)$/i);
if (snoozeDurationMatch) {
  post_id = snoozeDurationMatch[1];
  command = 'snooze_duration';
  command_args = `${post_id} ${snoozeDurationMatch[2].toLowerCase()}`;
  intent = 'SNOOZE_POST';
  setSnoozeDuration(snoozeDurationMatch[2]);
}

const callbackMatch = !snoozeDurationMatch ? callbackData.match(/^(hide_replies|ignore|snooze|resume|order_likes):([0-9]{1,19})$/) : null;
if (callbackMatch) {
  const callbackCommand = callbackMatch[1];
  post_id = callbackMatch[2];
  command = callbackCommand;
  command_args = post_id;

  if (callbackCommand === 'hide_replies') intent = 'HIDE_REPLIES';
  if (callbackCommand === 'ignore') intent = 'IGNORE_POST';
  if (callbackCommand === 'snooze') intent = 'SNOOZE_MENU';
  if (callbackCommand === 'resume') intent = 'RESUME_POST';
  if (callbackCommand === 'order_likes') {
    intent = 'ORDER_LIKES';
    like_amount = null;
    likes_prompt_required = true;
  }
}

const commandMatch = !snoozeDurationMatch && !callbackMatch ? text.match(/^\/(\w+)(?:@\w+)?(?:\s+([\s\S]*))?$/) : null;

function setPostIntent(nextIntent, commandName, args) {
  intent = nextIntent;
  command = commandName;
  const idMatch = String(args || '').match(/([0-9]{1,19})/);
  post_id = idMatch ? idMatch[1] : '';
}

function setSnoozeIntent(commandName, args) {
  command = commandName;
  const tokens = String(args || '').trim().split(/\s+/).filter(Boolean);
  post_id = /^[0-9]{1,19}$/.test(tokens[0] || '') ? tokens[0] : '';
  const duration = String(tokens[1] || '').toLowerCase();

  if (!post_id) {
    intent = 'SNOOZE_POST';
    return;
  }

  if (duration) {
    intent = 'SNOOZE_POST';
    if (!setSnoozeDuration(duration)) {
      snooze_duration_invalid = duration;
    }
    return;
  }

  intent = 'SNOOZE_MENU';
}

function setLikesIntent(commandName, args) {
  intent = 'ORDER_LIKES';
  command = commandName;
  const tokens = String(args || '').trim().split(/\s+/).filter(Boolean);
  post_id = /^[0-9]{1,19}$/.test(tokens[0] || '') ? tokens[0] : '';
  like_amount = tokens.length >= 2 ? tokens[1] : '';
  likes_prompt_required = Boolean(callbackQuery && post_id && tokens.length === 1);
  if (likes_prompt_required) like_amount = null;
}

function applyStartPayload(args) {
  const payload = String(args || '').trim();
  start_payload = payload;
  const normalized = payload.toLowerCase();

  if (['auth', 'auth_x', 'connect', 'connect_x'].includes(normalized)) {
    intent = 'AUTH_X';
    command = 'auth_x';
    command_args = '';
    return true;
  }

  const trackMatch = payload.match(/^track[-_](.+)$/i);
  if (trackMatch) {
    intent = 'TRACK_USERS';
    command = 'track';
    command_args = trackMatch[1].trim();
    return true;
  }

  return false;
}

function applyCompatibilityParsing() {
  if (lower === 'help' || lower === 'start') {
    intent = 'HELP';
    return;
  }

  const hideMatch = text.match(/hide\s+(?:the\s+)?replies\s+(?:of|for)\s+post\s*:?\s*([0-9]{1,19})/i)
    || text.match(/hide\s+post\s*:?\s*([0-9]{1,19})/i);
  if (hideMatch) {
    setPostIntent('HIDE_REPLIES', 'hide_replies', hideMatch[1]);
    return;
  }

  const actionMatch = text.match(/^(ignore|snooze|resume)(?:\s+(?:the\s+)?)?(?:post\s*)?:?\s*([0-9]{1,19})(?:\s+(\S+))?$/i);
  if (actionMatch) {
    const action = actionMatch[1].toLowerCase();
    const intentMap = {
      ignore: 'IGNORE_POST',
      resume: 'RESUME_POST',
    };
    if (action === 'snooze') {
      setSnoozeIntent(action, `${actionMatch[2]} ${actionMatch[3] || ''}`.trim());
      return;
    }
    setPostIntent(intentMap[action], action, actionMatch[2]);
  }
}

if (commandMatch) {
  command = commandMatch[1].toLowerCase();
  command_args = (commandMatch[2] || '').trim();

  switch (command) {
    case 'help':
      intent = 'HELP';
      break;

    case 'start':
      if (!applyStartPayload(command_args)) {
        intent = 'HELP';
      }
      break;

    case 'auth_x':
    case 'auth':
      intent = 'AUTH_X';
      break;

    case 'track':
      intent = 'TRACK_USERS';
      break;

    case 'hide_replies':
    case 'hide':
      setPostIntent('HIDE_REPLIES', command, command_args);
      break;

    case 'ignore':
      setPostIntent('IGNORE_POST', command, command_args);
      break;

    case 'snooze':
      setSnoozeIntent(command, command_args);
      break;

    case 'resume':
      setPostIntent('RESUME_POST', command, command_args);
      break;

    case 'order_comments':
      setPostIntent('ORDER_COMMENTS', command, command_args);
      break;

    case 'order_likes':
      setLikesIntent(command, command_args);
      break;

    default:
      intent = 'UNKNOWN';
  }
} else if (!snoozeDurationMatch && !callbackMatch) {
  applyCompatibilityParsing();
}

return [{
  json: {
    intent,
    command,
    command_args,
    start_payload,
    callback_query_id,
    callback_message_id,
    callback_message_text,
    telegram_chat_id: chatId,
    message_text: text,
    post_id,
    like_amount,
    likes_prompt_required,
    snooze_duration_key,
    snooze_duration_label,
    snooze_runs_remaining,
    snooze_duration_invalid,
    input_source,
  },
}];

const crypto = require('crypto');

// TODO: Replace these placeholders after import.
const clientId = 'Q285bFM0VUJLdlJHTk82aW5YcVE6MTpjaQ';
const redirectUri = 'https://tarek1207.app.n8n.cloud/webhook/x-oauth-callback';

const scopes = [
  'tweet.read',
  'users.read',
  'tweet.moderate.write',
  'offline.access',
];

function base64Url(buffer) {
  return buffer
    .toString('base64')
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=+$/, '');
}

function toQueryString(params) {
  return Object.keys(params)
    .map(key => `${encodeURIComponent(key)}=${encodeURIComponent(params[key])}`)
    .join('&');
}

if (clientId === 'YOUR_X_CLIENT_ID' || redirectUri === 'YOUR_N8N_CALLBACK_URL') {
  throw new Error('Replace YOUR_X_CLIENT_ID and YOUR_N8N_CALLBACK_URL before activating this workflow.');
}

const state = base64Url(crypto.randomBytes(32));
const codeVerifier = base64Url(crypto.randomBytes(32));
const codeChallenge = base64Url(
  crypto.createHash('sha256').update(codeVerifier).digest()
);

const expiresAt = new Date(Date.now() + 10 * 60 * 1000).toISOString();

const query = toQueryString({
  response_type: 'code',
  client_id: clientId,
  redirect_uri: redirectUri,
  scope: scopes.join(' '),
  state,
  code_challenge: codeChallenge,
  code_challenge_method: 'S256',
});

return [{
  json: {
    telegram_chat_id: $json.telegram_chat_id,
    state,
    code_verifier: codeVerifier,
    expires_at: expiresAt,
    auth_url: `https://x.com/i/oauth2/authorize?${query}`,
  },
}];

const route = $('Parse Telegram Message').first().json;
const post = $('Get Post For Hide').first()?.json || {};
const account = $input.first()?.json || $json || {};

const postId = String(route.post_id || post.post_id || '').trim();
const postOwnerUserId = String(post.user_id || '').trim();

function fail(error_message) {
  return [{
    json: {
      auth_ok: false,
      telegram_chat_id: route.telegram_chat_id,
      post_id: postId,
      post_owner_user_id: postOwnerUserId,
      error_message,
    },
  }];
}

if (!postId) {
  return fail('Please provide a post ID to hide replies for.');
}

if (!postOwnerUserId) {
  return fail('I could not find a stored flagged post owner for post ' + postId + '. Wait for monitoring to flag the post, then try hiding again.');
}

if (!account.access_token) {
  return fail('No authenticated X account was found for the owner of post ' + postId + '. Please authenticate that X account with /auth_x before hiding its replies.');
}

const accountUserId = String(account.x_user_id || '').trim();
if (accountUserId !== postOwnerUserId) {
  return fail('The selected X token does not own post ' + postId + '. Please authenticate the account whose X user ID is ' + postOwnerUserId + '.');
}

const expiresAtMs = account.expires_at ? new Date(account.expires_at).getTime() : 0;
const refreshBufferMs = 2 * 60 * 1000;
const tokenExpired = !expiresAtMs || Number.isNaN(expiresAtMs) || expiresAtMs <= Date.now() + refreshBufferMs;

if (tokenExpired && !account.refresh_token) {
  return fail('The X connection for the account that owns post ' + postId + ' expired. Please send /auth_x again.');
}

return [{
  json: {
    auth_ok: true,
    token_needs_refresh: tokenExpired,
    telegram_chat_id: route.telegram_chat_id,
    auth_telegram_chat_id: account.telegram_chat_id || route.telegram_chat_id,
    post_id: postId,
    post_owner_user_id: postOwnerUserId,
    post_text: post.post_text || '',
    x_user_id: accountUserId,
    x_username: account.x_username || '',
    access_token: account.access_token,
    refresh_token: account.refresh_token || '',
    expires_at: account.expires_at,
    scope: account.scope || '',
  },
}];

// TODO: Replace these placeholders after import.
const clientId = 'Q285bFM0VUJLdlJHTk82aW5YcVE6MTpjaQ';
const clientSecret = 'ZAApmo-Z6kzX-fYYyyWjCffziJfRNP8yVURxEdIgyYmKoea3nH';

if (clientId === 'YOUR_X_CLIENT_ID' || clientSecret === 'YOUR_X_CLIENT_SECRET') {
  throw new Error('Replace YOUR_X_CLIENT_ID and YOUR_X_CLIENT_SECRET before activating this workflow.');
}

const auth = Buffer.from(`${clientId}:${clientSecret}`).toString('base64');

return [{
  json: {
    ...$json,
    authorization: `Basic ${auth}`,
  },
}];

const previous = $('Prepare Refresh Request').first().json;
const refreshed = $json || {};

if (!refreshed.access_token) {
  throw new Error('X token refresh did not return an access_token. Send /auth_x again.');
}

const expiresInSeconds = Number(refreshed.expires_in || 0);
const expiresAt = expiresInSeconds > 0
  ? new Date(Date.now() + expiresInSeconds * 1000).toISOString()
  : previous.expires_at;

return [{
  json: {
    telegram_chat_id: previous.telegram_chat_id,
    auth_telegram_chat_id: previous.auth_telegram_chat_id || previous.telegram_chat_id,
    post_id: previous.post_id,
    post_owner_user_id: previous.post_owner_user_id,
    post_text: previous.post_text || '',
    x_user_id: previous.x_user_id,
    x_username: previous.x_username || '',
    access_token: refreshed.access_token,
    refresh_token: refreshed.refresh_token || previous.refresh_token,
    expires_at: expiresAt,
    scope: refreshed.scope || previous.scope || '',
    updated_at: new Date().toISOString(),
  },
}];

let account = $json || {};
let refreshed = {};

try {
  refreshed = $('Prepare Refreshed Account').first()?.json || {};
} catch (error) {
  refreshed = {};
}

if (refreshed.access_token) {
  account = refreshed;
} else if (!account.access_token) {
  account = refreshed;
}

return [{
  json: {
    telegram_chat_id: account.telegram_chat_id,
    auth_telegram_chat_id: account.auth_telegram_chat_id || account.telegram_chat_id,
    post_id: account.post_id,
    post_owner_user_id: account.post_owner_user_id,
    post_text: account.post_text || '',
    x_user_id: account.x_user_id,
    x_username: account.x_username || '',
    access_token: account.access_token,
    refresh_token: account.refresh_token || '',
    expires_at: account.expires_at,
    scope: account.scope || '',
  },
}];

const account = $('Prepare Account For Replies').first().json;

const replies = $input.all()
  .map(item => item.json || {})
  .filter(reply => reply.reply_id);

if (replies.length === 0) {
  return [{
    json: {
      has_replies: false,
      telegram_chat_id: account.telegram_chat_id,
      post_id: account.post_id,
      message: 'No stored replies found for post ' + account.post_id + '.',
    },
  }];
}

return replies.map(reply => ({
  json: {
    has_replies: true,
    telegram_chat_id: account.telegram_chat_id,
    post_id: account.post_id,
    x_user_id: account.x_user_id,
    x_username: account.x_username || '',
    access_token: account.access_token,
    reply_id: String(reply.reply_id),
    text: reply.text || '',
  },
}));

return $input.all().map((item, index) => {
  const original = $('Build Reply Hide Items').all()[index].json;
  const response = item.json || {};
  const success = response?.data?.hidden === true && !response.error;
  const errorMessage = response.error?.message || response.error || response.message || '';

  return {
    json: {
      reply_id: original.reply_id,
      post_id: original.post_id,
      text: original.text,
      status: success ? 'hidden' : 'hide_failed',
      hidden_success: success,
      error_message: typeof errorMessage === 'string' ? errorMessage : JSON.stringify(errorMessage),
      telegram_chat_id: original.telegram_chat_id,
    },
  };
});

const results = $('Prepare Hide Result').all().map(item => item.json);
const first = results[0] || {};
const hidden = results.filter(result => result.hidden_success).length;
const failed = results.length - hidden;

return [{
  json: {
    telegram_chat_id: first.telegram_chat_id,
    post_id: first.post_id,
    hidden,
    failed,
    total: results.length,
    message: `Hide replies complete.\nPost: ${first.post_id}\nHidden: ${hidden}\nFailed: ${failed}`,
  },
}];

const route = $('Parse Telegram Message').first().json;
const text = route.command_args || route.message_text || '';

function normalizeUsername(value) {
  return String(value || '')
    .trim()
    .replace(/^https?:\/\/(?:www\.)?(?:x|twitter)\.com\//i, '')
    .replace(/^@+/, '')
    .split(/[/?#]/)[0]
    .replace(/[^A-Za-z0-9_]/g, '')
    .toLowerCase();
}

const candidates = [];

for (const match of text.matchAll(/@([A-Za-z0-9_]{1,15})/g)) {
  candidates.push(match[1]);
}

for (const match of text.matchAll(/(?:https?:\/\/)?(?:www\.)?(?:x|twitter)\.com\/([A-Za-z0-9_]{1,15})(?:[/?#]|$)/gi)) {
  candidates.push(match[1]);
}

let cleanedText = text
  .replace(/(?:https?:\/\/)?(?:www\.)?(?:x|twitter)\.com\/[A-Za-z0-9_]{1,15}(?:[/?#][^\s]*)?/gi, ' ')
  .replace(/@[A-Za-z0-9_]{1,15}/g, ' ')
  .replace(/^\/track(?:@\w+)?/i, ' ')
  .replace(/\b(track|tracking|accounts?|users?|usernames?|x|twitter|please|pls|add|the|following|and|or|to|of)\b/gi, ' ');

for (const part of cleanedText.split(/[\s,;:]+/)) {
  candidates.push(part);
}

const reserved = new Set([
  'home', 'explore', 'notifications', 'messages', 'i', 'intent', 'search',
  'settings', 'compose', 'share', 'status', 'post', 'posts', 'reply', 'replies',
]);

const usersArray = [...new Set(
  candidates
    .map(normalizeUsername)
    .filter(user => /^[a-z0-9_]{1,15}$/.test(user))
    .filter(user => !reserved.has(user))
)];

if (usersArray.length === 0) {
  return [{
    json: {
      users_valid: false,
      telegram_chat_id: route.telegram_chat_id,
      usersToTrack: [{ user: '' }],
      message: '',
    },
  }];
}

return [{
  json: {
    users_valid: true,
    telegram_chat_id: route.telegram_chat_id,
    usersToTrack: usersArray.map(user => ({ user })),
    message: `Successfully tracking the following users:\n- ${usersArray.join('\n- ')}`,
  },
}];

const route = $('Parse Telegram Message').first().json;
const post = $input.first()?.json || {};

function escapeHtml(value) {
  return String(value || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/\"/g, '&quot;');
}

function buildEditedAlert(values) {
  const source = route.callback_message_text || `Post ${values.post_id || route.post_id}`;
  const base = escapeHtml(source).slice(0, 3500);
  const statusLine = values.action_valid
    ? `<b>XMonitor status:</b> ${escapeHtml(values.message)}`
    : `<b>XMonitor status:</b> ${escapeHtml(values.message || values.callback_text || 'Action rejected.')}`;
  return `${base}\n\n${statusLine}`;
}

function result(values) {
  const payload = {
    telegram_chat_id: route.telegram_chat_id,
    callback_query_id: route.callback_query_id || '',
    callback_message_id: route.callback_message_id || '',
    post_id: String(route.post_id || ''),
    action_valid: false,
    show_resume: false,
    next_status: '',
    snooze_runs_remaining: 0,
    callback_text: '',
    ...values,
  };
  payload.edited_alert_message = buildEditedAlert(payload);
  return [{ json: payload }];
}

if (!route.post_id) {
  return result({
    message: 'Please provide a valid post ID.',
    callback_text: 'Missing post ID.',
  });
}

if (!post.post_id) {
  return result({
    message: `Post ${route.post_id} was not found. Wait for monitoring to flag it, then try again.`,
    callback_text: 'Post not found.',
  });
}

const currentStatus = String(post.status || 'New');

if (route.intent === 'SNOOZE_POST' && currentStatus === 'Ignored') {
  return result({
    current_status: currentStatus,
    message: `Post ${route.post_id} is ignored. Resume it before snoozing.`,
    callback_text: 'Resume the post before snoozing.',
  });
}

if (route.intent === 'SNOOZE_POST' && route.snooze_duration_invalid) {
  return result({
    current_status: currentStatus,
    message: `Unsupported snooze duration "${route.snooze_duration_invalid}". Choose one of: 1h, 4h, 12h, 24h.`,
    callback_text: 'Unsupported snooze duration.',
  });
}

if (route.intent === 'SNOOZE_POST' && !Number.isInteger(Number(route.snooze_runs_remaining))) {
  return result({
    current_status: currentStatus,
    message: 'Please choose a snooze duration: 1h, 4h, 12h, or 24h.',
    callback_text: 'Choose a snooze duration.',
  });
}

if (route.intent === 'IGNORE_POST') {
  return result({
    action_valid: true,
    current_status: currentStatus,
    next_status: 'Ignored',
    snooze_runs_remaining: 0,
    show_resume: true,
    message: `Post ${route.post_id} is now ignored and will not generate scheduled alerts.`,
    callback_text: 'Post ignored.',
  });
}

if (route.intent === 'SNOOZE_POST') {
  const runs = Number(route.snooze_runs_remaining);
  const durationLabel = route.snooze_duration_label || `${runs} hour${runs === 1 ? '' : 's'}`;
  return result({
    action_valid: true,
    current_status: currentStatus,
    next_status: 'Snoozed',
    snooze_runs_remaining: runs,
    show_resume: true,
    message: `Post ${route.post_id} is snoozed for ${durationLabel} (${runs} schedule run${runs === 1 ? '' : 's'}).`,
    callback_text: `Post snoozed for ${durationLabel}.`,
  });
}

if (route.intent === 'RESUME_POST') {
  return result({
    action_valid: true,
    current_status: currentStatus,
    next_status: 'New',
    snooze_runs_remaining: 0,
    show_resume: false,
    message: `Post ${route.post_id} is active again and can appear in scheduled alerts.`,
    callback_text: 'Post resumed.',
  });
}

return result({
  current_status: currentStatus,
  message: 'Unsupported post status action.',
  callback_text: 'Unsupported action.',
});

// Get all reply rows coming into this Code node
const replies = $input.all().map(item => item.json);

const post = $('Store Comment Order Post').first().json;

const payload = {
  post: {
    id: post.post_id || post.id || post.current_post_id,
    content: post.content || post.text || post.current_post_content,
  },
  replies: replies.map(reply => ({
    reply_id: String(reply.reply_id),
    post_id: String(reply.post_id),
    text: reply.text,
  })),
};

return [
  {
    json: payload,
  },
];

