const rows = $input.all().map(item => item.json);

if (rows.length === 0) {
  throw new Error('No rows received from Supabase.');
}

const commentsArray = rows
  .map(row => row.counter_reply_text)
  .filter(comment => comment !== null && comment !== undefined)
  .map(comment => String(comment).trim())
  .filter(comment => comment.length > 0);

if (commentsArray.length < 10) {
  throw new Error(`Service 8404 requires at least 10 comments. You provided ${commentsArray.length}.`);
}

if (commentsArray.length > 250) {
  throw new Error(`Service 8404 allows a maximum of 250 comments. You provided ${commentsArray.length}.`);
}

const formattedComments = commentsArray.join('\n');

return [
  {
    json: {
      post_id: String(rows[0].post_id),
      comments: formattedComments,
      commentCount: commentsArray.length
    }
  }
];

const maxLength = 3000;
const comments = $('Build Comment Order Payload').first().json.comments || '';

let text = '';

if (Array.isArray(comments)) {
  text = comments
    .map((comment, index) => `${index + 1}. ${String(comment).trim()}`)
    .join('\n\n');
} else {
  text = comments
    .split('\n')
    .map(comment => comment.trim())
    .filter(comment => comment !== '')
    .map((comment, index) => `${index + 1}. ${comment}`)
    .join('\n\n');
}

const chunks = [];

for (let i = 0; i < text.length; i += maxLength) {
  chunks.push({
    json: {
      message: text.slice(i, i + maxLength),
      chunkIndex: chunks.length + 1,
    },
  });
}

return chunks;

