  if (lower.includes('fund') || lower.includes('balance') || lower.includes('credit')) {
    code = 'insufficient_funds';
    userMessage = 'I could not place the comment order because the SMM provider balance does not have enough funds.';
  } else if (lower.includes('key') || lower.includes('api') || lower.includes('auth')) {
    code = 'provider_auth_error';
    userMessage = 'I could not place the comment order because the SMM provider credentials were rejected. Please check the provider API key.';
  } else if (lower.includes('service')) {
    code = 'invalid_or_unavailable_service';
    userMessage = `I could not place the comment order because the configured SMM service was rejected: ${errorText}`;
  } else if (lower.includes('link') || lower.includes('url')) {
