  } else if (lower.includes('quantity') || lower.includes('minimum') || lower.includes('maximum') || lower.includes('min') || lower.includes('max')) {
    code = 'invalid_quantity';
    userMessage = `I could not place the comment order because the requested amount is outside the provider limits: ${errorText}`;
  } else if (lower.includes('comment')) {
    code = 'invalid_comments';
    userMessage = `I could not place the comment order because the generated comments were rejected: ${errorText}`;
  } else if (lower.includes('duplicate') || lower.includes('already')) {
    code = 'duplicate_order';
    userMessage = `I could not place the comment order because the provider says this order may already exist: ${errorText}`;
