    userMessage = 'I could not place the likes order because the SMM provider is rate limiting requests. Please try again later.';
  } else if (lower.includes('maintenance') || lower.includes('unavailable') || lower.includes('temporarily')) {
    code = 'provider_unavailable';
    userMessage = 'I could not place the likes order because the SMM provider is temporarily unavailable. Please try again later.';
  }

  return { code, errorText, userMessage };
}

const providerOrderId = String(addResponse.order || '').trim();
const providerError = addResponse.error || addResponse.Error || addResponse.message || addResponse.Message;

if (!providerOrderId || providerError) {
  const classification = classifyProviderError(addResponse);
  return [{
    json: {
      order_ok: false,
      order_error_code: classification.code,
      order_error_message: classification.errorText,
      order_user_message: classification.userMessage,
      provider: 'smmwiz',
      provider_add_response: addResponse,
      order_type: 'likes',
      post_id: String(storedPost.current_post_id || ''),
      telegram_chat_id: String(route.telegram_chat_id || ''),
      x_username: String(storedPost.current_post_username || ''),
      link: String(request.link || '').trim(),
      service_id: String(request.serviceId || ''),
      quantity,
      comment_count: null,
    },
  }];
}

return [{
  json: {
    order_ok: true,
    provider: 'smmwiz',
    provider_order_id: providerOrderId,
    order_type: 'likes',
    post_id: String(storedPost.current_post_id || ''),
    telegram_chat_id: String(route.telegram_chat_id || ''),
    x_username: String(storedPost.current_post_username || ''),
    link: String(request.link || '').trim(),
    service_id: String(request.serviceId || ''),
    quantity,
    comment_count: null,
    request_payload: { quantity },
    provider_add_response: addResponse,
    provider_status: 'Pending',
    normalized_status: 'pending',
    next_check_at: new Date().toISOString(),
  },
}];

